CREATE TABLE IF NOT EXISTS public.kanban_boards (id uuid PRIMARY KEY, workspace_id text NOT NULL, name text NOT NULL, is_default boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(workspace_id,name));
CREATE UNIQUE INDEX IF NOT EXISTS idx_kanban_default_board ON public.kanban_boards(workspace_id) WHERE is_default;
CREATE TABLE IF NOT EXISTS public.kanban_stages (id uuid PRIMARY KEY, board_id uuid NOT NULL REFERENCES public.kanban_boards(id), key text NOT NULL, name text NOT NULL, position numeric NOT NULL, is_terminal boolean NOT NULL DEFAULT false, is_archived_stage boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(board_id,key), UNIQUE(board_id,position));
CREATE TABLE IF NOT EXISTS public.conversation_kanban_state (workspace_id text NOT NULL, conversation_id uuid NOT NULL, board_id uuid NOT NULL REFERENCES public.kanban_boards(id), stage_id uuid NOT NULL REFERENCES public.kanban_stages(id), position numeric NOT NULL, manual_override boolean NOT NULL DEFAULT false, last_transition_source text NOT NULL, last_transition_by uuid NULL, last_transition_at timestamptz NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(conversation_id,board_id), FOREIGN KEY(workspace_id, conversation_id) REFERENCES public.conversations(workspace_id,id));
CREATE INDEX IF NOT EXISTS idx_kanban_state_stage ON public.conversation_kanban_state(board_id,stage_id,position);
CREATE TABLE IF NOT EXISTS public.conversation_kanban_events (id uuid PRIMARY KEY, workspace_id text NOT NULL, conversation_id uuid NOT NULL, board_id uuid NOT NULL, from_stage_id uuid NULL, to_stage_id uuid NOT NULL, source text NOT NULL, actor_id uuid NULL, metadata_safe jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_kanban_events_conversation ON public.conversation_kanban_events(workspace_id,conversation_id,created_at DESC);
GRANT SELECT, INSERT, UPDATE ON public.kanban_boards, public.kanban_stages, public.conversation_kanban_state, public.conversation_kanban_events TO service_role;
